/**
 * Cached OS detection - only runs once on client side
 * Returns null during SSR, then caches the result after first check
 */
let cachedIsMac: boolean | null = null

const getIsMac = () => {
  // Return cached value if available
  if (cachedIsMac !== null) return cachedIsMac

  // During SSR, default to false (ChevronUp)
  if (typeof window === 'undefined') return false

  // Cache the result on first client-side check
  cachedIsMac = /Mac|iPod|iPhone|iPad/.test(window.navigator.platform)
  return cachedIsMac
}

/**
 * MetaIcon - Dynamic icon that shows Command on macOS and ChevronUp on Windows/Linux
 * Used for keyboard shortcuts to show the appropriate meta key icon
 */
export const MetaIcon = (props: Omit<IconProps, 'dark'>) => {
  const IconComponent = getIsMac() ? Command : ChevronUp
  return <IconComponent {...props} />
}
